sql:
SELECT songs.name AS song_name, artists.artist_name AS artist_name
FROM songs
INNER JOIN artists ON songs.artists_id = artists.artist_id;

SELECT s.name AS song_name
FROM songs s
WHERE s.popularity > (SELECT AVG(popularity) FROM songs);

SELECT song_id, SUM(play_count) as TotalPlays
FROM user_playback
GROUP BY song_id;

SELECT name 
FROM songs 
WHERE popularity >= 100;

SELECT * FROM songs 
ORDER BY duration_ms DESC 
LIMIT 1;
